INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (1, 1, 1, 'Avoid Arching Your Back: One common mistake is excessively arching the back during the lift. This can lead to lower back injuries. Your lower back should have a natural arch, but it should not be overly exaggerated. Your butt, shoulders, and head should maintain contact with the bench at all times.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (2, 1, 2, 'Controlled Movement: Avoid the temptation to lift the barbell too quickly. A controlled, steady lift is more effective and reduces the risk of injury. Lower the bar to your mid-chest slowly, pause briefly, then push it back up without locking your elbows at the top.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (3, 1, 3, 'Don''t Lift Alone:', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (4, 2, 1, 'Grip: Hold the dumbbells with a neutral grip (palms facing each other). This grip allows for a greater range of motion and less strain on the shoulders compared to a traditional grip. Avoid gripping the dumbbells too tightly as this can lead to wrist strain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (5, 2, 2, 'Elbow Alignment: When you lower the dumbbells, make sure your elbows are slightly below your shoulders. This alignment helps to engage the chest muscles effectively. A common mistake is allowing the elbows to flare out to the sides, which can lead to shoulder injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (6, 2, 3, 'Controlled Movement: Lower the dumbbells slowly and in a controlled manner,', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (7, 3, 1, 'Maintain Proper Body Alignment: Your body should form a straight line from your head to your heels. Avoid arching your back or lifting your buttocks, as this can lead to back pain and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (8, 3, 2, 'Controlled Movements: Avoid rushing through the movements. Lower your body in a controlled manner until your chest almost touches your hands, then push back up. This will ensure you''re fully engaging your muscles and not relying on momentum.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (9, 3, 3, 'Don''t Lock Your Elbows: When you push your body up, avoid locking your elbows, as it can put unnecessary strain on your joints. Keep a slight bend in your elbows at the top of the movement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (10, 3, 4, 'Warm', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (11, 4, 1, 'Proper Grip: Hold the dumbbell with a neutral grip, meaning your palms should be facing each other. This is where the ''hammer'' in the name comes from, as your hand positioning should resemble holding a hammer. Avoid gripping the dumbbell too tightly as this can lead to unnecessary forearm fatigue.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (12, 4, 2, 'Controlled Movement: As you press the dumbbell upwards, ensure your movement is slow and controlled. Avoid the common mistake of using momentum to lift the weight, as this can lead to muscle strain and doesn''t effectively engage the targeted muscles. At the top of the movement, your arm should be fully extended but not locked out.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (13, 5, 1, 'Controlled Movement: This exercise involves lowering the dumbbell until your elbow is at a 90-degree angle, then pressing it back up to the starting position. It''s important to perform this motion in a slow, controlled manner. Avoid the temptation to use momentum or to perform the exercise too quickly, as this can lead to poor form and potential injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (14, 5, 2, 'Use Appropriate Weight: Using a weight that''s too heavy can compromise your form and increase your risk of injury. Start with a lighter weight and gradually increase as you get stronger. The last couple of reps should feel challenging, but you should still be able to maintain good form.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (15, 5, 3, 'Avoid Locking Your Elbows: When pressing the dumbbell', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (16, 7, 1, 'Proper Hand Position: Your hands should be slightly wider than shoulder-width apart. Avoid gripping the bar too wide or too narrow, as this can strain the shoulders and limit the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (17, 7, 2, 'Controlled Movement: Lift and lower the weights in a slow, controlled manner. Avoid jerking the weights or using momentum to lift them, as this can lead to injury and reduces the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (18, 7, 3, 'Avoid Locking Elbows: When you press the weights up, avoid locking your elbows at the top of the movement. This can put unnecessary strain on the joints and lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (19, 7, 4, 'Breathing Technique: Breathe in as you lower the weights and breathe out as you lift', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (20, 8, 1, 'Controlled Movements: Avoid rushing through the movements. The Arnold Press should be performed slowly and controlled, both when lifting and lowering the weights. This not only ensures the targeted muscles are fully engaged, but also reduces the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (21, 8, 2, 'Right Weight: Select a weight that is challenging but manageable. Using weights that are too heavy can lead to improper form and increase the risk of injury. On the other hand, weights that are too light might not provide enough resistance to effectively work the muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (22, 8, 3, 'Breathing Technique: Remember to breathe correctly. Inhale as you lower the weights', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (23, 9, 1, 'Avoid Using Momentum: Another common mistake is using momentum to lift the weights. This not only reduces the effectiveness of the exercise, but it also increases the risk of injury. Focus on using your muscles to lift the weights, not the momentum of the swing.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (24, 9, 2, 'Right Weight Selection: Choosing the right weight is crucial. If the weight is too heavy, it can lead to improper form and potential injury. Conversely, if it''s too light, you', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (25, 10, 1, 'Engage Your Core: As you lower your body by bending your elbows, maintain a tight core. This helps to stabilize your body and protect your spine. A common mistake is to let the core go loose, which can cause strain on your back and shoulder muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (26, 10, 2, 'Proper Elbow Alignment: While lowering your body, ensure your elbows are bent at a 90-degree angle and pointing back, not flaring out to the sides. This is crucial for targeting the triceps effectively and avoiding unnecessary strain on the shoulders.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (27, 10, 3, 'Controlled Movement: Avoid rushing through the movement. Lower your body in a slow, controlled manner and push back up to the starting position. This ensures', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (28, 11, 1, 'Avoiding Knee Overextension: A common mistake is extending the knees too far forward, beyond the toes. This can put unnecessary pressure on the knees and lead to injury. Instead, make sure your knees are aligned with your feet during the squat.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (29, 11, 2, 'Depth of Squat: Aim for a deep squat where your hips go below your knees. However, do not compromise on form or safety to achieve this. If you can''t squat that deep without losing form, it''s better to do a shallower squat.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (30, 11, 3, 'Breathing Technique: Your breathing technique can greatly influence your performance. Inhale as you lower your body and exhale as you push yourself back up', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (31, 12, 1, 'Foot Placement: Your feet should be slightly wider than shoulder-width apart, with toes pointing slightly outward. This provides a stable base for the squat. Avoid placing your feet too close together as it can make it difficult to maintain balance and can put undue stress on your knees.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (32, 12, 2, 'Squat Depth: Aim to lower your body until your elbows touch your knees or your thighs are parallel to the floor. This ensures you''re getting the full range of motion and maximum benefits from the exercise. Avoid not going deep enough as it can limit the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (33, 12, 3, 'Keep Your Chest Up and Back Straight: One common mistake is', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (34, 13, 1, 'Controlled Movement: Avoid rushing the movements. Each step of the Squat Thrust should be performed in a controlled manner. Rushing can lead to sloppy form, which not only reduces the effectiveness of the exercise but also increases risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (35, 13, 2, 'Full Range of Motion: Make sure to perform the exercise through its full range of motion. When you squat, go as low as your flexibility allows, ideally until your thighs are parallel to the floor. When you kick back into the plank, extend your legs fully. Cutting these movements short can limit the benefits of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (36, 13, 3, 'Keep the Core Engaged: Throughout the exercise, keep your core muscles engaged. This', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (37, 14, 1, 'Proper Form: The key to an effective Sissy Squat is maintaining proper form throughout the movement. Stand upright with your feet shoulder-width apart. As you bend your knees to lower your body, lean your torso backwards to maintain balance. Keep your back straight and avoid hunching or arching it excessively as this can lead to back injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (38, 14, 2, 'Controlled Movement: A common mistake is rushing through the exercise or using momentum to complete the movement. Instead, perform each rep slowly and with control. This will engage your muscles more effectively and reduce the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (39, 14, 3, 'Use Assistance if Needed: If you''re new to Sissy Squats', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (40, 15, 1, 'Maintain Upright Posture: It''s important to keep your body upright throughout the movement. Leaning too far forward can put unnecessary strain on your lower back and shift the focus away from your lower body muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (41, 15, 2, 'Avoid Knee Overextension: Never let your front knee extend past your toes as you lower your body. This is a common mistake that can lead to knee injuries. Instead, make sure your knee is in line with your ankle.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (42, 15, 3, 'Controlled Movement: Don''t rush the movement. Lower your body in a controlled manner and then push back up to the starting position. This will ensure that you''re effectively engaging your muscles and not relying on', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (43, 16, 1, 'Squat Depth: When you squat down, make sure your thighs are at least parallel to the floor. Avoid the common mistake of not squatting deep enough, as this can limit the effectiveness of the exercise and place undue stress on your knees.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (44, 16, 2, 'Explosive Jump: The key to this exercise is the jumping component. As you rise from the squat, push through your heels and explode upwards, jumping as high as possible. A common mistake is not jumping with enough force, which can limit the exercise''s effectiveness in strengthening your lower body and improving your vertical jump.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (45, 16, 3, 'Controlled Landing: Land softly and quietly, absorbing the impact with your legs by bending your knees and returning to the squat position', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (46, 17, 1, 'Keep Your Chest Up: One common mistake is leaning too far forward or allowing the back to round. To avoid this, focus on keeping your chest lifted and your spine neutral throughout the exercise. This will also engage your core muscles more effectively.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (47, 17, 2, 'Depth of Squat: In a sumo squat, aim to lower your body until your thighs are parallel to the floor. Going too low (past parallel) can put undue stress on your knees, while not going low enough may not fully engage the muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (48, 17, 3, 'Knee Alignment: Ensure your knees are directly above your ankles when you squat down, not jutting forward over your toes. This will help to prevent knee injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (49, 17, 4, 'Push Through Your Heels: When coming back up to standing position, push', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (50, 18, 1, 'Maintain Good Posture: Always keep your torso upright throughout the exercise. Leaning too far forward or backward can put unnecessary strain on your back, leading to potential injury. The chest should be up and the shoulders back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (51, 18, 2, 'Depth of the Squat: Aim for your front thigh to be parallel with the ground at the bottom of your squat. If you can''t reach this depth, it''s likely that your stance is too narrow. Conversely, if you''re going deeper than this, your stance might be too wide.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (52, 18, 3, 'Don''t Let Your Knee Cave In: When you lower yourself into the squat, make sure your front knee is tracking over your foot. If your', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (53, 19, 1, 'Correct Form: Maintain a correct posture throughout the exercise. Start with your feet shoulder-width apart, bend your knees and hips to lower your body into a squat, then explosively jump up. When you land, make sure to do so softly and go directly into the next squat. Keep your chest up and back straight, and don''t let your knees cave inwards.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (54, 19, 2, 'Control Your Landing: A common mistake is landing hard on your feet, which can lead to injuries. Always aim to land softly and quietly, absorbing the impact through your legs. Your knees should be slightly bent upon landing.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (55, 19, 3, 'Use Your Arms: Your arms can help you generate more power and maintain balance. As you squat', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (56, 20, 1, 'Controlled Movements: One common mistake is rushing through the exercise. Make sure to perform the movement slowly and with control, lowering yourself as far as you can comfortably go, then pushing back up to the starting position. This enhances muscle engagement and reduces the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (57, 20, 2, 'Keep Core Engaged: Your core should be tight throughout the exercise. This will help you maintain balance and stability, especially since you''re performing the exercise on a single leg. Avoid letting your torso lean too far forward or sideways as this can lead to an incorrect form and potential injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (58, 20, 3, '', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (59, 21, 1, 'Maintain a Neutral Spine: One common mistake is rounding the back during the movement, which can lead to injury. Instead, keep your back straight and your core engaged throughout the exercise. Your shoulders should be back and down, not hunched.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (60, 21, 2, 'Hinge at the Hips: The Romanian Deadlift is a hip-hinge movement, meaning the action comes from bending at the hips, not the waist. Push your hips back as you lower the weights towards the ground, keeping them close to your legs to avoid straining your lower back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (61, 21, 3, 'Don’t Lock Your Knees: Another common mistake is to lock your knees during the exercise. Your', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (62, 22, 1, 'Correct Foot Placement: Stand with your feet shoulder-width apart. Do not position your feet too wide or too narrow as it can compromise your balance and the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (63, 22, 2, 'Controlled Movements: Lower the dumbbells slowly and controlled, hinging at the hips. Avoid the mistake of using a fast, jerking motion to lift the weights. This can lead to muscle strain and does not effectively work the targeted muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (64, 22, 3, 'Right Weight: Choose a weight that is challenging but manageable. One common mistake is lifting too heavy too soon, which can compromise form and lead to injury. Start with lighter weights and gradually increase as your strength improves.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (65, 22, 4, 'Engage Your Core: Keep your abs braced throughout the exercise. This', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (66, 23, 1, 'Arm and Leg Extension: As you lower your body, extend your non-supporting leg and the opposite arm in a straight line. This requires balance and coordination, so take your time and don''t rush the movement. The common mistake is to let the arm or the leg droop, which can throw off your balance and alignment.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (67, 23, 2, 'Controlled Movements: This exercise is not about speed, but control. Lower your body slowly, and then push back up to the starting position in a controlled manner. Avoid jerky movements which can lead to muscle strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (68, 23, 3, 'Don''t Lock the Knee: Keep a slight bend in your', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (69, 24, 1, 'Avoid Overextending: A common mistake is to lower the weights too far, which can strain the lower back. Aim to lower the weights to just below your knees or until you feel a stretch in the hamstrings, then return to the starting position.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (70, 24, 2, 'Engage Your Core and Glutes: To get the most out of the exercise, it''s important to engage your core and squeeze your glutes as you lift the weights back up. This will help to stabilize your body and increase the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (71, 24, 3, 'Don''t Rush: Another mistake to avoid is rushing', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (72, 25, 1, 'Keep Your Focus: Balance is key in this exercise. To help maintain balance, find a fixed point in front of you and keep your gaze on it throughout the movement. This will help you stay steady and ensure you are performing the exercise correctly.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (73, 25, 2, 'Use Your Hips: The single leg deadlift is a hip hinge movement, meaning the action should come from your hips, not your knees. Push your hips back as you lower your body and drive them forward as you return to the standing position.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (74, 25, 3, 'Avoid Rushing: Many people rush through the exercise, which can lead to a loss of balance and poor form. Take your time with each repetition', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (75, 26, 1, 'Full Foot Contact: Ensure your entire foot, from heel to toe, is in contact with the pedal throughout the movement. Some people tend to push through their toes, which can strain the calf muscles and reduce the overall effectiveness of the workout.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (76, 26, 2, 'Use the Handles: The handles are there to help engage your upper body. However, avoid pulling on them with too much force as this can lead to an imbalance and strain your arms. Instead, lightly grip the handles and use them to guide your motion.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (77, 26, 3, 'Appropriate Resistance and Speed: Start with a low resistance level and gradually increase it as your strength and endurance improve. Avoid setting the resistance too high as it can lead to strain and injury. Similarly, don''t', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (78, 27, 1, 'Warm Up and Cool Down: Always start your workout with a 5 to 10 minute warm-up at a slower pace to get your muscles ready for the exercise. Similarly, end your session with a cool-down period to gradually reduce your heart rate and prevent muscle stiffness.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (79, 27, 2, 'Gradual Increase in Speed and Incline: Don''t start walking at a high speed or incline. Begin your workout at a comfortable pace and gradually increase the intensity. This will help prevent injuries and ensure that you don''t burn out too quickly.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (80, 27, 3, 'Avoid Overstriding: A common mistake is taking long strides to increase the speed or to make the', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (81, 28, 1, 'Correct Foot Placement: Your feet should be flat on the pedals at all times. This will help you engage more muscles and reduce the risk of injury. Avoid pushing through your toes, which can lead to foot or calf discomfort.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (82, 28, 2, 'Hand Placement: If your elliptical machine has handles, use them to work your upper body. However, make sure not to grip them too tightly or lean on them, as this can put unnecessary strain on your wrists and arms.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (83, 28, 3, 'Use the Resistance and Incline Settings: One common mistake is not utilizing the various settings on the elliptical. Adjusting the resistance and incline can help you target different muscle groups and add variety to your workout, making it more', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (84, 29, 1, 'Avoid Holding onto the Handrails: One of the common mistakes people make is holding onto the handrails while running. This can lead to an unnatural running form and limit the amount of calories you burn. Instead, let your arms swing naturally as they would if you were running outdoors.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (85, 29, 2, 'Use the Incline Wisely: To mimic outdoor running, set your incline to at least 1-2%. Running on a flat treadmill can be easier than running outside because there''s no wind resistance. However, don''t set the incline too high (over 7%) as this can be hard on your back, hips, and ankles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (86, 29, 3, 'Don''t Look Down: Looking down or watching your feet while running', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (87, 30, 1, 'Gradual Increase: Start with a small incline and gradually increase it over time. This will allow your body to adjust to the new exercise intensity and reduce the risk of injury.    Common Mistake: Suddenly increasing the incline can lead to muscle strains or other injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (88, 30, 2, 'Appropriate Speed: Don''t try to maintain the same speed you use on a flat surface. The incline makes the exercise more challenging, so you''ll likely need to slow down to maintain a steady pace.    Common Mistake: Attempting to walk too fast on an incl', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (89, 31, 1, 'Engage Your Core: To get the most out of the Suspended Row, it''s important to engage your core throughout the entire exercise. This not only helps to stabilize your body but also maximizes the strength you can gain from the exercise. A common mistake is to focus only on pulling with your arms, while ignoring your core.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (90, 31, 2, 'Controlled Movement: Ensure that your movements are slow and controlled. Avoid the temptation to use momentum to pull yourself up, as this can lead to injury and makes the exercise less effective. Instead, focus on pulling yourself up using your', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (91, 32, 1, 'Controlled Movements: When you pull the weight up, do so in a controlled manner, ensuring that your elbow is close to your body. Similarly, lower the weight in a controlled manner. Avoid jerky or fast movements, as this can lead to muscle strain and doesn''t effectively work the targeted muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (92, 32, 2, 'Focus on the Right Muscles: The One Arm Bent-over Row primarily targets the muscles in your back, so it''s important to consciously engage these muscles during the exercise. Avoid the common mistake of using your b', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (93, 33, 1, 'Control the Weight: Don''t let the weight control you. A common mistake is to use momentum to lift the weight, rather than engaging the muscles. This can lead to poor form and potential injury. Instead, lift the weight in a slow, controlled motion, focusing on the muscle contraction and relaxation.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (94, 33, 2, 'Choose the Right Weight: It''s important to choose a weight that is challenging but manageable. A common mistake is to use a weight that is too heavy, which can lead to poor form and potential injury. Start with a lighter weight and gradually increase as your strength improves.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (95, 33, 3, '', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (96, 34, 1, 'Avoid Straining Your Neck: A common mistake is straining the neck by looking up or tucking the chin into the chest. To avoid this, try to keep your neck in a neutral position by looking at the floor or slightly ahead.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (97, 34, 2, 'Engage Your Core: Engaging your core is crucial for this exercise. It not only helps to keep your body stable but also protects your lower back. Avoid arching your back excessively as this can lead to lower back pain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (98, 34, 3, 'Controlled Movements: Perform the exercise', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (99, 35, 1, 'Secure Grip: When holding the towel, make sure you have a firm and secure grip. The towel should be held taut throughout the movement. A common mistake is holding the towel too loosely, which can lead to an uneven pull and potential strain on your wrists or hands.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (100, 35, 2, 'Controlled Movement: The movement of pulling the towel towards your body and then releasing it should be slow and controlled. Avoid the mistake of using momentum or jerky movements, which can lead to injuries and less effective muscle engagement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (101, 35, 3, 'Engage Core: Remember to engage your core muscles as you perform the row. This not only helps in maintaining your balance but also adds an extra layer of workout for your', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (102, 36, 1, 'Maintain Good Posture: It''s crucial to keep your back straight and your core engaged throughout the exercise. Slouching or hunching can cause strain on your back and neck and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (103, 36, 2, 'Controlled Movements: When pulling the towel down, ensure your movements are slow and controlled. Avoid jerking or using momentum to pull the towel down, as this can lead to muscle strain and doesn''t effectively engage your muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (104, 36, 3, 'Breathing: Remember to breathe during the exercise. Inhale as you raise the towel above your head, and exhale as you pull it down. Holding', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (105, 37, 1, 'Gentle Movements: When performing the forward flexion neck stretch, use slow, gentle movements. Avoid jerking or forcing your neck into position. This is a common mistake that can lead to injury. Instead, gradually lower your chin towards your chest until you feel a stretch in the back of your neck.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (106, 37, 2, 'Hold and Breathe: Hold the stretch for about 15-30 seconds. Remember to breathe normally during this time. Holding your breath can increase tension and decrease the effectiveness of the stretch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (107, 37, 3, 'Repeat: Repeat the stretch 2-4 times. Don’t rush through the repetitions. Take your time to ensure each stretch is performed correctly and safely.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (108, 37, 4, 'Listen to Your Body: Avoid pushing too hard. If you feel pain or discomfort, ease off', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (109, 38, 1, 'Grip and Position: Hold the dumbbells in your hands with palms facing towards you. Your hands should be slightly less than shoulder-width apart. Avoid holding the dumbbells too wide or too close as this can strain your wrists and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (110, 38, 2, 'Smooth and Controlled Movement: Raise the dumbbells in front of you until your arms are slightly above parallel to the floor. Make sure the movement is slow and controlled, both when lifting and lowering the dumbbells. Avoid swinging or using momentum to lift the weights, as this can lead to injury and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (111, 38, 3, 'Breathing Technique: Breathe out as you lift the weights and breathe in as you lower them.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (112, 39, 1, 'Engage Your Core: The key to an effective crunch is to engage your core muscles. As you lift your upper body off the floor, focus on contracting your abdominal muscles. Do not pull on your neck or use your arms for momentum, as this can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (113, 39, 2, 'Controlled Movement: Perform each crunch with slow, controlled movements. Avoid the common mistake of rushing through the exercise, as this can lead to poor form and less effective muscle engagement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (114, 39, 3, 'Breathing Technique: Breathe out as you lift your body and breathe in as you lower it back down. This helps keep your core engaged throughout the exercise and can make the crunch more effective.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (115, 39, 4, 'Avoid Neck Strain: A', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (116, 40, 1, 'Avoid Swinging: A common mistake is to use momentum to lift the weights, often by swinging the arms or twisting the torso. This not only reduces the effectiveness of the exercise but also increases the risk of injury. To avoid this, focus on performing the exercise slowly and with control.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (117, 40, 2, 'Breathe Correctly: Breathing correctly is essential for any exercise, including the Hammer Curl. Exhale as you lift the dumbbells and inhale as you lower them. This will help to maintain your blood pressure and prevent dizziness.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (118, 40, 3, 'Choose Appropriate Weight: Using weights', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (119, 41, 1, 'Controlled Movements: As you pull the towel towards you, bending your knees, ensure your movements are slow and controlled. This will not only help you maintain balance but also maximize muscle engagement. Avoid jerky or quick movements, which can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (120, 41, 2, 'Engage Your Core: While the primary focus is on your biceps, don''t forget to engage your core. This will provide stability and support, preventing unnecessary pressure on your back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (121, 41, 3, 'Avoid Overstretching: When extending your legs, avoid pushing them to a point where your back arches off the floor. This common mistake can put undue stress on your lower back and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (122, 41, 4, 'Consistent Breathing: Breathe out as', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (123, 42, 1, 'Proper Grip: Hold the dumbbell with an overhand grip (palm facing down). Your grip should be firm but not overly tight to avoid straining your wrist. A common mistake is gripping the weight too tightly which can lead to wrist strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (124, 42, 2, 'Controlled Movement: Lower the dumbbell as far as possible, then curl it up as high as you can. The movement should be slow and controlled. Avoid the common mistake of using quick, jerky movements which can lead to injury and won''t effectively target the muscles you''re trying to strengthen.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (125, 42, 3, 'Keep Your Arm Still: Your arm should remain still throughout the exercise, with only your hand and wrist moving. A', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (126, 43, 1, 'Controlled Movement: Avoid using momentum or swinging your arms to lift the towel. Instead, focus on using your biceps to pull the towel towards your chest. This controlled movement will ensure that your muscles are properly engaged, leading to more effective results.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (127, 43, 2, 'Breathing Technique: Proper breathing is crucial for any exercise. Inhale as you lower the towel and exhale as you curl it up. This will help maintain your energy levels and ensure that your muscles receive enough oxygen.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (128, 43, 3, 'Consistent Tension: Keep the towel taut throughout the exercise. This constant resistance will engage your biceps throughout the entire movement,', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (129, 44, 1, 'Controlled Movements: When you curl the weight, do so in a smooth and controlled manner. Avoid jerky movements or using momentum to lift the weight. This not only reduces the effectiveness of the exercise but also increases the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (130, 44, 2, 'Avoid Overloading: It can be tempting to use heavy weights to accelerate results, but it''s crucial to choose a weight that allows you to perform the exercise with the correct form. Using too heavy weights can lead to improper form and potential injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (131, 44, 3, 'Breathing Technique: Proper breathing is essential for this exercise. Exhale as you curl the weight towards your shoulder, and inh', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (132, 45, 1, 'Control the Weight: Do not use a weight that is too heavy for you. This can lead to improper form or injury. Start with a lighter weight and gradually increase as you get stronger. Always control the weight both on the way up and on the way down, don''t let it fall or use momentum to lift it.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (133, 45, 2, 'Full Range of Motion: Ensure you are using a full range of motion. This means lowering the weight until your wrist is fully extended and then raising it until your wrist is fully flexed. Avoid partial reps, as this can limit the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (134, 45, 3, 'Keep Your Wrist Straight: Avoid bending your wrist to the side or twisting it during the exercise. This can', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (135, 46, 1, 'Controlled Movement: When you curl the towel upwards towards your shoulders, make sure to do it in a controlled manner. Do not use your back or shoulders to lift the weight; your biceps should do all the work. Jerky movements can cause harm and reduce the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (136, 46, 2, 'Full Range of Motion: To get the maximum benefit from the Two Legs Hammer Curl with Towel, ensure you''re using a full range of motion. Lower the towel all the way down before curling it back up. Not using the full range of motion can limit the growth and strength of your biceps.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (137, 46, 3, 'Breathing Technique', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (138, 47, 1, 'Maintain Control: Avoid using momentum to lift the weight. This is a common mistake that can lead to injury and reduces the effectiveness of the exercise. Keep your movements slow and controlled, focusing on the muscle contraction and relaxation.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (139, 47, 2, 'Full Range of Motion: To get the most out of this exercise, ensure you''re using a full range of motion. This means lowering the weight all the way down until your arm is fully extended, then curling it back up as far as it will comfortably go.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (140, 47, 3, 'Avoid Elbow Movement: Your elbow should remain stationary throughout the exercise. If your elbow is moving, it', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (141, 48, 1, 'Controlled Movement: When performing the curl, bend your knees and pull them towards your chest using the towel, then slowly extend them back out. The key is to control the movement both when pulling and extending your legs. Avoid rushing the movement or using momentum to swing your legs, as this can lead to injury and reduces the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (142, 48, 2, 'Engage Your Core: Keep your abs and glutes engaged throughout the exercise. This will not only help to stabilize your body but also enhances the workout by working your core muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (143, 48, 3, 'Breathing Technique: One common mistake is holding your breath during the exercise. For maximum benefit, breathe out as you pull your knees towards your chest and', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (144, 49, 1, 'Engage Your Core: Before you start the curl, engage your core muscles. This not only helps to protect your lower back but also ensures that the focus of the exercise remains on your upper body. A common mistake is to neglect the core and rely on momentum to lift the body, which can lead to injuries and less effective workouts.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (145, 49, 2, 'Controlled Movements: Ensure that your movements are slow and controlled. Avoid the common mistake of jerking or using momentum to lift your body. Instead, use your arm and shoulder strength to pull your chin over the chairs. Lower yourself back down with the same controlled motion.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (146, 50, 1, 'Controlled Movements: Execute each movement slowly and with control. Avoid jerky or rapid movements which can strain the muscles. This is a common mistake many people make. Remember, the effectiveness of this stretch comes from control, not speed.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (147, 50, 2, 'Correct Arm Position: Your arms should be at a 90-degree angle with your palms facing down. Avoid overextending your arms or bending them too much as this can lead to injury and reduce the effectiveness of the stretch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (148, 50, 3, 'Engage Your Shoulder Muscles: When performing the stretch, make sure to engage your shoulder muscles. This means actively pulling your shoulders down and back. A common mistake is to merely move the arms without engaging', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (149, 51, 1, 'Engage Your Core: One common mistake is not engaging the core. The L-Pull-up not only targets your upper body, but also your core. Ensure your abs are tight and engaged throughout the exercise. This will help maintain the L shape and also provide stability.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (150, 51, 2, 'Avoid Using Momentum: Swinging or using momentum to pull yourself up is a common mistake. This can lead to injury and also reduces the effectiveness of the exercise. Instead, focus on using your upper body strength to pull yourself up in a controlled', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (151, 52, 1, 'Correct Form and Technique: Ensure that you maintain the correct form throughout the exercise. Your body should be straight from head to toe, and your hands should be shoulder-width apart. Avoid bending your elbows and knees. Also, make sure to pull your body up using your lats and not your arms. A common mistake is using the arms to do the pulling, which can lead to strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (152, 52, 2, 'Controlled Movement: The movement should be slow and controlled, both when pulling up and lowering down. Avoid jerky or fast movements as they can lead to injury and won''t engage your muscles effectively.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (153, 52, 3, 'Breathing: Proper breathing is essential during this exercise. Inhale as you lower your body and exhale as you', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (154, 53, 1, 'Engage the Right Muscles: Pull-ups primarily work your back muscles, but they can also engage your arms and shoulders if done correctly. One common mistake is using too much arm strength and not enough back. Try to focus on pulling your elbows down and back, rather than pulling yourself up with your arms. This will help engage the right muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (155, 53, 2, 'Avoid Kipping: Kipping, or using a swinging motion to help propel yourself up, is a common mistake. While this may allow you to do more pull-ups, it reduces the effectiveness of', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (156, 54, 1, 'Warm Up: Before you start your commando pull-ups, make sure to warm up properly. This can include a light cardio session or dynamic stretches to get your muscles ready for the exercise. Jumping straight into commando pull-ups without a warm-up can strain your muscles and lead to injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (157, 54, 2, 'Grip Strength: Commando pull-ups require a good amount of grip strength. If you''re struggling with the exercise, it might be because your grip strength needs improvement. Consider incorporating grip strengthening exercises', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (158, 55, 1, 'Proper Form: Start by gripping the tops of the chairs with your palms facing away from you. Bend your knees at a 90-degree angle and cross your ankles. Use your upper body strength to pull yourself up until your chin is above the level of the chairs. Avoid using momentum or swinging your body to pull yourself up; this is a common mistake that can lead to injury and reduces the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (159, 55, 2, 'Controlled Movement: Lower yourself back down in a slow and controlled manner until your arms are fully extended. Avoid dropping down quickly, as this can strain your muscles and joints.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (160, 55, 3, 'Breathing Technique: Breathe in as you lower yourself and breathe out as you pull yourself up. This helps maintain', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (161, 56, 1, 'Avoid Using Momentum: One common mistake is using body momentum to perform the pull-up. This not only reduces the effectiveness of the exercise but also increases the risk of injury. Instead, focus on using your back and arm muscles to pull yourself up and lower yourself down.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (162, 56, 2, 'Engage Your Core: Engaging your core is essential for maintaining proper form during the exercise. It helps to stabilize your body, preventing unnecessary swinging and ensuring that your back and arm muscles are doing the work.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (163, 56, 3, 'Don''t Rush: Another common mistake is performing the exercise too quickly. Instead, try to perform the pull-up in a slow and controlled manner. This will', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (164, 57, 1, 'Avoid Using Momentum: A common mistake is using momentum to pull yourself up. This can lead to injury and doesn''t engage your muscles as effectively as a controlled, steady movement. Instead of swinging or kicking your legs, focus on using your upper body strength to lift yourself.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (165, 57, 2, 'Engage Your Core: Engaging your core muscles is crucial for maintaining stability during the pull-up. This will also help prevent unnecessary swinging and will ensure your body rises in a controlled manner.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (166, 57, 3, 'Full Range of Motion: To get the most out of the exercise, make sure you''re using a full', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (167, 58, 1, 'Correct Foot Position: Your feet should be hip-width apart. Try to press your heels down towards the floor. If you''re a beginner or have tight hamstrings, it''s okay if your heels don''t touch the ground. Avoid walking your feet too close to your hands, as this can put unnecessary strain on your shoulders and neck.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (168, 58, 2, 'Engage Your Core and Legs: This pose is not just about flexibility, but also about strength. Engage your core muscles and quadriceps to lift your hips up and back. This will help to take some pressure off your wrists and shoulders. A common mistake is to let the belly and ribs sag towards the floor, which can put', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (169, 59, 1, 'Correct Stretching Technique: Reach out with your other hand and gently pull your fingers down and towards your body until you feel a stretch in your forearm. Keep your arm straight during this process to ensure that the stretch is targeting the correct muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (170, 59, 2, 'Maintain Control: It''s crucial to avoid jerky movements or pulling too hard on your wrist. This could lead to strains or injuries. Instead, ensure that your movements are smooth and controlled, increasing the stretch gradually.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (171, 59, 3, 'Hold and Release: Hold the stretch for about 20-30 seconds, then release slowly. This will allow your muscles to relax and adapt to the stretch. Avoid releasing the stretch abruptly as it could lead to muscle strain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (172, 59, 4, 'Common Mistakes to Avoid:', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (173, 60, 1, 'Controlled Movement: Avoid swinging the weights. Instead, lift and lower them in a controlled manner. This not only ensures you''re working the right muscles but also reduces the risk of injury. A common mistake is to use momentum to lift the weights, which can lead to ineffective exercise and potential injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (174, 60, 2, 'Correct Arm Position: Keep your elbows slightly bent and raise your arms to the sides until they''re parallel with the floor. A common mistake is to raise the arms too high or too low, which can lead to shoulder strain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (175, 60, 3, 'Weight Selection: Choose a weight that allows you to complete the set with good form but is still challenging. If the weight is too heavy, it can lead to poor', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (176, 61, 1, 'Proper Foot Placement: Your feet should be together, with the soles touching each other. Avoid having your feet too far away from your body as it can put unnecessary strain on your hips and lower back. Ideally, your feet should be as close to your groin as comfortably possible.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (177, 61, 2, 'Gentle Push: While pushing your knees down with your elbows, make sure you are not forcing them. Listen to your body and only push as far as it feels comfortable. Overstretching can lead to injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (178, 61, 3, 'Breathing Technique: Breathing correctly is vital in any yoga pose. In the Butterfly Pose, inhale while lifting', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (179, 62, 1, 'Engage Your Core: The Front Plank is a core exercise, so it''s essential to engage your abdominal muscles. Avoid the common mistake of holding your breath during the exercise. Instead, breathe normally and focus on tightening your abs, as if you were bracing for a punch to the stomach.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (180, 62, 2, 'Keep Your Neck and Spine Neutral: Another common mistake is craning your neck upwards or looking down at your feet. This can put unnecessary strain on your neck. Instead, keep your gaze slightly ahead of you on the floor and maintain a neutral neck and spine position.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (181, 62, 3, 'Start Slow and Increase Grad', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (182, 63, 1, 'Controlled Movement: It''s important to avoid fast, jerky movements when performing hyperextensions. You should lower your upper body towards the floor slowly and in a controlled manner, then raise your torso back up to the starting position. Fast or uncontrolled movements can put unnecessary strain on your back and lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (183, 63, 2, 'Maintain a Neutral Spine: Throughout the exercise, keep your spine in a neutral position. This means you should avoid rounding or excessively arching your back. A common mistake is to hyperextend the back at the top of the movement, which can', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (184, 64, 1, 'Controlled Movements: Avoid rushing through the exercise or using momentum to swing your body up and down. This can lead to lower back strain or injury. Instead, focus on slow, controlled movements. Lower your upper body towards the ground, then use your lower back and glute muscles to lift your torso back to the starting position.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (185, 64, 2, 'Engage Your Core: Another common mistake is not engaging the core during the exercise. Always remember to keep your core engaged throughout the movement. This helps to protect your lower back and ensures that the right muscles are being targeted.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (186, 64, 3, 'Maintain a Neutral Spine: To avoid straining your neck or', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (187, 65, 1, 'Proper Grip: Hold the rope attachment with both hands behind your head. Your palms should be facing towards each other and your fingers should be interlocked. Avoid holding the rope too tightly as this could cause unnecessary tension in your hands and arms.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (188, 65, 2, 'Controlled Movement: The movement should be slow and controlled. Extend your neck backwards, using the muscles at the back of your neck to pull the weight. Avoid jerking or using momentum to lift the weight, as this could lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (189, 65, 3, 'Range of Motion: Make sure to fully extend your neck without going beyond your comfortable range of motion. Avoid overextending as this could lead to strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (190, 65, 4, 'Breathing: Breathe', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (191, 66, 1, 'Controlled Movements: Perform the extension slowly and with control. Quick, jerky movements can lead to injury. Instead, gradually lift your hand up as far as you can, hold for a moment, and then lower it back down slowly.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (192, 66, 2, 'Avoid Overextension: A common mistake is to overextend the wrist, which can lead to strain or injury. Always listen to your body and only extend your wrist to a point that is comfortable for you.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (193, 66, 3, 'Use Light Weights: If you are using a dumbbell or a resistance band for this exercise, start with a light weight or low resistance. This will help you to focus on your form and avoid injury. You can gradually increase the weight or resistance as you', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (194, 67, 1, 'Slow and Steady: When performing the extension and inclination neck stretch, move slowly and gently. Rapid, jerky movements can lead to muscle strain or injury. Extend your neck backwards slowly until you feel a gentle stretch, then tilt your head from one side to the other.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (195, 67, 2, 'Don''t Overstretch: A common mistake people make is to overstretch, which can lead to muscle strain or injury. You should feel a gentle pull, not pain. If you feel any discomfort, ease back until the stretch is comfortable.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (196, 67, 3, 'Breathe: Don''t hold your breath while stretching. Breathe deeply and evenly throughout the exercise. Holding your breath can cause tension in your neck and shoulders, which can make the stretch', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (197, 68, 1, 'Slow and Controlled Movements: When performing the flexion and extension, make sure your movements are slow and controlled. Avoid jerky or rapid movements that can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (198, 68, 2, 'Range of Motion: While performing the exercise, it''s important to not overextend or force your neck beyond its comfortable range of motion. Listen to your body and stop if you feel any discomfort or pain.', NULL);
