INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (201, 69, 1, 'Engage Your Core: Engaging your core is essential for stability and balance during the Supination Bar Suspension Stretch. This will also help to protect your lower back. To do this, pull your belly button in towards your spine and keep your abdominal muscles tight throughout the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (202, 69, 2, 'Control Your Movements: Avoid swinging or bouncing while performing the stretch. Instead, focus on slow, controlled movements. This not only increases the effectiveness of the exercise but also reduces the risk of injury.', NULL);
