INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (204, 70, 1, 'Controlled Movement: Avoid quick, jerky movements. Instead, slowly bend your elbow and then slowly straighten it again. This controlled movement will ensure that you''re effectively working the muscles and not relying on momentum.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (205, 70, 2, 'Full Range of Motion: To get the most out of the exercise, make sure you''re using the full range of motion. This means fully extending and flexing the elbow. Not doing so can lead to muscle imbalances and can limit the effectiveness of the exercise.', NULL);
