INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (208, 71, 1, 'Controlled Movements: When performing the exercise, ensure your movements are slow and controlled. Avoid jerking or using momentum to lift the weight. This is a common mistake that can lead to injury and reduces the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (209, 71, 2, 'Correct Weight: Start with a light weight and gradually increase it as your strength improves. Using too heavy a weight from the start can strain your neck muscles and lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (210, 71, 3, 'Range of Motion: Ensure you are moving through the full range of motion, from a full extension to a complete flexion. This will ensure all the muscles in the neck are being worked effectively.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (211, 71, 4, 'Rest and Recovery: Don''t overdo this exercise. The neck muscles are delicate and can easily be overworked. Rest adequately', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (212, 72, 1, 'Avoid Using Momentum: Avoid using momentum to swing the weights up, as this can lead to injury and reduces the effectiveness of the exercise. Instead, lift and lower the weights in a controlled manner, focusing on the muscles you''re trying to work.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (213, 72, 2, 'Choose the Right Weight: Using too heavy weights can lead to poor form and potential injuries. Start with lighter weights and gradually increase as your strength improves. Remember, the goal is not to lift the heaviest weight, but to perform the exercise correctly and safely.', NULL);
