INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (215, 73, 1, 'Controlled Movement: Avoid bouncing or using momentum to lift the weight. This is a common mistake that can lead to injury and also reduces the effectiveness of the exercise. Instead, lift and lower the weight in a slow, controlled manner, focusing on the muscle contraction and relaxation.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (216, 73, 2, 'Full Range of Motion: Make sure to use the full range of motion. Lower your heels as much as you can to stretch your calves, then lift as high as possible to contract them. Not using the full range of motion can limit the benefits of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (217, 73, 3, 'Proper Weight: Don''t use too much weight. If you can''t perform the exercise with proper form, you''re likely using too much weight. This is a common mistake that can lead to injury.5', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (218, 74, 1, 'Controlled Movement: Avoid rushing through the movements. Instead, raise your heels slowly, hold at the top for a moment to maximize the contraction in your calf muscles, and then lower your heels slowly. This controlled movement helps to prevent injury and ensures you''re effectively working your muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (219, 74, 2, 'Full Range of Motion: Make sure to go through the full range of motion. This means lowering your heels below the level of the step at the bottom of the movement, and raising your heels as high as possible at the top. Not using the full range of motion is a common mistake that can limit the effectiveness of the exercise', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (220, 75, 1, 'Controlled Movement: When raising your leg, do so in a slow and controlled manner. Avoid the common mistake of using momentum to lift your leg, as this can lead to lower back strain and reduces the effectiveness of the exercise on your abdominal muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (221, 75, 2, 'Keep Your Lower Back Pressed Down: A common mistake is arching the lower back off the floor, which can cause back pain and injury. To avoid this, keep your lower back pressed firmly against the floor during the entire movement. You can achieve this by engaging your core and imagining you''re trying to press your belly button down to the floor.', NULL);
