INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (227, 77, 2, 'Control Your Movement: Avoid bouncing or using momentum to lift your body. Instead, lift and lower your body in a controlled, steady motion. This will ensure you''re effectively working your calf muscles and not relying on momentum to do the work.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (228, 77, 3, 'Keep Your Feet Parallel: Another common mistake is turning the feet outward or inward during the exercise. Keep your feet parallel to each other to ensure that you''re working', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (229, 78, 1, 'Controlled Movement: Raise your legs off the ground to a 90-degree angle. The key is to do this slowly and with control, rather than using momentum to swing your legs up. Using momentum can reduce the effectiveness of the exercise and potentially lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (230, 78, 2, 'Engage Your Core: Ensure that your lower back is pressed into the floor and your core is engaged throughout the exercise. This will help you avoid straining your back and will also maximize the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (231, 78, 3, 'Hold and Lower: At the top of the movement, hold the position for a few seconds before slowly lowering your legs back down. Do not let your legs touch the floor until the set is complete', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (232, 79, 1, 'Foot Position: Your feet should be hip-width apart and flat on the floor or the edge of a step if you''re doing the exercise with a raised platform. Avoid pointing your toes inward or outward as this could strain your ankles.', NULL);
