INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (234, 79, 3, 'Range of Motion: Try to raise your heels as high as possible to engage the full range of motion of your calf muscles. However, avoid overextending your ankles or pushing beyond your comfort level as this could lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (235, 79, 4, 'Use Support: If you''re new to the exercise or have balance', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (236, 80, 1, 'Proper Grip: Hold the towel at both ends, keeping your arms straight. The towel should be taut, but not so tight that it restricts movement. Ensure that your grip is firm but comfortable to avoid any unnecessary strain on your wrists.', NULL);
