INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (238, 80, 3, 'Breathing: Maintain a steady breathing pattern throughout the exercise. Inhale as you raise your arms and exhale as you lower them. This helps to maintain a steady rhythm and ensures that your muscles receive enough oxygen.', NULL);
