INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (244, 82, 2, 'Correct Knee Positioning: When you bring your knee up, it should be parallel to the ground. Also, when you step into the lunge, make sure your front knee is directly above your ankle, not pushed out too far in front. Misalignment can lead to knee injuries.', NULL);
