INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (247, 83, 2, 'Mind Your Pace: Don''t rush through your lunges. Performing them at a slow, controlled pace will help you maintain balance and focus on your form. It also ensures that your muscles are fully engaged throughout the exercise.', NULL);
