INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (249, 84, 1, 'Core Engagement: Engage your core throughout the exercise. This will help maintain balance and stability, and also protect your lower back from strain. It''s a common mistake to let your core relax, causing a bend or arch in your back, which can lead to injury.', NULL);
