INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (253, 86, 2, 'Core Engagement: Engage your core throughout the entire movement. This not only helps with balance but also works your abdominal muscles.', NULL);
