INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (255, 87, 1, 'Avoid Leaning Forward: A common mistake is leaning too far forward when performing a side lunge. This can put unnecessary stress on your knees and back. Instead, keep your chest lifted and your spine neutral throughout the movement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (256, 87, 2, 'Control Your Movement: Side lunges should be done in a controlled manner. Avoid rushing through the movement or using momentum to carry you from side to side. This will ensure you''re effectively working your muscles and not risking injury.', NULL);
