INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (258, 88, 1, 'Controlled Movement: As you lower your body towards the ground, keep your elbows close to your body. Push back up, and as you do, rotate your upper body to one side, lifting the same-side arm towards the ceiling. Repeat the movement, alternating sides. Avoid rushing through the movements. Each phase of the push-up should be done in a slow, controlled manner to maximize muscle engagement and prevent injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (259, 88, 2, 'Core Engagement: Keep your core engaged throughout the exercise. This will not only help to stabilize your body but also enhance the effectiveness of the push-up. A common mistake is to forget', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (260, 89, 1, 'Correct Positioning: Start by kneeling on one knee with your other foot in front of you, toes pointing upwards. Your front leg should be straight, and your back should be upright. Avoid arching your back or bending your front leg, as these are common mistakes that can lead to injury or reduce the effectiveness of the stretch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (261, 89, 2, 'Gradual Stretch: Lean forward from your hips, keeping your back straight, until you feel a stretch in the hamstring of your front leg. Don''t bounce or force the stretch - this is a common mistake that can cause muscle strain. The stretch should be gradual and controlled.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (262, 89, 3, 'Hold and Breathe: Hold the stretch for at least 15-30', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (263, 90, 1, 'Controlled Movements: Avoid flailing or uncontrolled movements. Each punch should be deliberate and controlled. Extend your arm fully but don''t lock your elbow when you punch. This can lead to injury. Instead, keep a slight bend in your elbow even at the end of the punch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (264, 90, 2, 'Body Rotation: A common mistake is to only use the arms while punching. The power of a punch actually comes from the rotation of your body. As you punch, twist your torso and pivot on your back foot. This will not only add power to your punch but also engage your core muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (265, 90, 3, 'Breathing: Don''t hold your breath while punching. Exhale with each punch and inhale as you', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (266, 91, 1, 'Slow and Steady Movement: Lower the weights slowly towards your forehead by bending at the elbows. The weights should be lowered until they''re about an inch from your forehead. Avoid the common mistake of moving your upper arms; they should remain stationary throughout the exercise. Rushing through the movement can lead to poor form and less effective muscle engagement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (267, 91, 2, 'Proper Elbow Alignment: Your elbows should be pointed towards your feet and not flaring out to the sides. This is a common mistake that can lead to shoulder strain. Keeping your elbows in helps to better isolate the triceps.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (268, 91, 3, 'Engage Your Core: While the focus is on your arms, don', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (269, 92, 1, 'Correct Posture: One common mistake is incorrect posture. Make sure to sit upright on the bike, with your chest out and shoulders back. Avoid hunching over as this can lead to back strain. Also, ensure that your feet are flat on the pedals and your hands are gripping the handles firmly but not too tightly.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (270, 92, 2, 'Balanced Effort: The Assault Bike Run is a full-body workout, so it''s essential to use both your arms and legs equally. A common mistake is to rely too much on either the upper or lower body. To avoid this, focus on pushing and pulling the handles while also pedaling with your legs.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (271, 92, 3, 'Pacing: Avoid starting off too fast. It''s better to start with a moderate pace', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (272, 93, 1, 'Proper Form: Make sure your form is correct. Stand tall with your feet hip-width apart. As you bend forward to touch your toes, keep your back straight and bend from your hips, not your waist. A common mistake is rounding the back, which can lead to strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (273, 93, 2, 'Don''t Force It: Never force your body to reach your toes if it''s not possible initially. It''s okay if you can''t touch your toes. The goal is to feel a stretch in your hamstrings, not to reach your toes. Over time, as your flexibility improves, you''ll be able to reach further.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (274, 93, 3, 'Breathe: Remember to breathe normally throughout the exercise. Holding your breath', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (275, 94, 1, 'Controlled Movements: It''s crucial to perform the exercise with slow, controlled movements. Rushing through the movements can lead to improper form and potential injury. When transitioning from your forearms to your hands, make sure to keep your core engaged and your body in a straight line. Avoid swaying or dipping your hips, which is a common mistake.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (276, 94, 2, 'Elbow Alignment: When you push up from your forearms, ensure your elbow aligns directly under your shoulder. This helps to avoid unnecessary strain on your shoulder joints. A common mistake is to place the hands too far forward, causing the elbows to move out of alignment.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (277, 94, 3, 'Breathing: It''s', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (278, 95, 1, 'Controlled Movement: When performing the toe tap, make sure to move your leg out to the side in a controlled manner, tap your toe to the ground, and then bring it back to the starting position. Avoid rushing through the movement or using momentum, as this can lead to improper form and potential injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (279, 95, 2, 'Engage Core: Keep your core engaged throughout the entire exercise to stabilize your body. This not only helps to protect your lower back but also maximizes the effectiveness of the exercise. A common mistake is to let the core relax, which can strain the lower back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (280, 95, 3, 'Keep Neck Neutral: Avoid straining your neck by looking too far up or down. Keep your gaze down', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (281, 96, 1, 'Controlled Movement: When performing the leg lift, it''s crucial to keep your movements controlled and deliberate. Avoid swinging or jerking your leg upwards as this can strain your lower back and won''t effectively engage the targeted muscles. Lift your leg only to a height that allows you to maintain a straight back and engaged core.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (282, 96, 2, 'Core Engagement: The front plank with leg lift is a core exercise, so ensure your abs, glutes, and back muscles are engaged throughout the entire movement. If your hips sag or your back arches, it''s a sign that your core is not properly engaged, which can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (283, 96, 3, 'Breathing: Another common mistake is holding your breath during', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (284, 97, 1, 'Controlled Movements: Slowly push your foot down, as if pressing on a gas pedal, then slowly return to the starting position. The key here is to perform the movement in a controlled manner, avoid jerky or rushed motions which can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (285, 97, 2, 'Consistent Repetitions: Aim for consistency in your repetitions. A common mistake is to do too many reps too quickly. Instead, focus on doing a set number of repetitions, such as 10 to 15, and gradually increase as your strength improves.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (286, 97, 3, 'Avoid Overextension: A common mistake is to push too hard, leading to overextension of the ankle. This can result in strain or injury. Always listen to your body and stop if you feel any pain.', NULL);
