INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (288, 98, 1, 'Correct Positioning: Make sure to position your foot correctly. Your heel should be firmly on the ground, and your toes should be pointing upwards. Avoid any sideways movement as it can lead to ankle sprains.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (289, 98, 2, 'Controlled Movements: The most common mistake is to rush through the exercise. It''s essential to perform each movement slowly and with control. Rapid or jerky movements can lead to injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (290, 98, 3, 'Use of Props: If you''re having trouble performing the exercise, consider using a towel or resistance band. Place the prop around the ball of your foot and gently pull towards you to help with the upward movement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (291, 98, 4, 'Regular Breaks: Don''t overdo it. If you feel any pain or discomfort, stop the exercise immediately. It', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (292, 99, 1, 'Proper Form: When stretching, make sure your form is correct. For a basic ankle stretch, sit on the floor with your legs extended in front of you. Reach forward with your hands and gently pull your toes back towards your body. Make sure to keep your back straight and don''t hunch over to reach your feet. This will ensure you''re stretching your ankles and not straining your back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (293, 99, 2, 'Gradual Stretch: Avoid bouncing or jerky movements when stretching. These can cause micro-tears in the muscle, leading to pain and injury. Instead, gradually increase the stretch over a period of 15-30 seconds. This allows your muscles', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (294, 100, 1, 'Proper Posture: Ensure that you maintain the right posture while performing the feet and ankles stretch. Stand tall with your feet hip-width apart and your weight evenly distributed on both feet. Avoid leaning too far forward or backward, as this can strain your muscles and lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (295, 100, 2, 'Gradual Stretching: When stretching your feet and ankles, make sure to do it gradually. Avoid bouncing or making jerky movements, which can cause injury. Instead, hold each stretch for about 20 to 30 seconds, release, and then repeat.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (296, 100, 3, 'Listen to Your Body: While it''s normal to feel a gentle pull or slight discomfort when stretching, you should never feel pain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (297, 101, 1, 'Correct Posture: While performing the feet and ankles rotation stretch, make sure you are in the correct posture. You can sit or stand, but your back should be straight. A common mistake is to slouch or lean too much into the stretch which can cause strain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (298, 101, 2, 'Controlled Movement: Make sure your rotations are slow and controlled. Avoid jerky movements as they can lead to injuries. The key here is to focus on the quality of the movement rather than the quantity.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (299, 101, 3, 'Both Directions: It''s important to rotate your feet and ankles in both directions to ensure balanced stretching. A common mistake is to only rotate in one direction, which can lead to imbalances.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (300, 101, 4, 'Don''t Overstretch: Stretch', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (301, 102, 1, 'Correct Positioning: Start the exercise by sitting on the floor with your legs extended in front of you. Keep your back straight and avoid slouching. This position will help you stretch your feet and ankles effectively without straining your back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (302, 102, 2, 'Controlled Movements: When moving your feet and ankles side to side, make sure to do so in a controlled manner. Avoid quick, jerky movements as these can lead to sprains or strains. Instead, focus on slow, deliberate movements that allow you to feel the stretch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (303, 102, 3, 'Don''t Overstretch: Stretch to the point of mild tension, not pain. If you feel pain, you''re stretching too far. Overstretching can cause injury to your muscles and ligaments.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (304, 102, 4, 'Regular Practice', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (305, 103, 1, 'Maintain Proper Form: Start in a traditional push-up position, with your body forming a straight line from your head to your heels. When you push up, propel your body upwards with enough force to clap your hands together before landing. It''s crucial to maintain proper form throughout the exercise, as incorrect form can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (306, 103, 2, 'Land Softly: One common mistake is landing too hard after the clap. This can be harmful to your wrists and elbows. To avoid this, make sure to land softly with your elbows slightly bent to absorb the shock.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (307, 103, 3, 'Start Slowly: If you''re new to clap push-ups, don''t rush. Trying to perform too many reps', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (308, 104, 1, 'Maintain Proper Body Alignment: Keep your body in a straight line from your head to your heels. Don''t let your back sag or your buttocks stick up in the air. This is a common mistake that can lead to back or shoulder injuries. Engage your core to help maintain this alignment.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (309, 104, 2, 'Controlled Movement: Avoid rushing the push-up. Lower your body slowly and push back up to the starting position in a controlled manner. This ensures you''re using your muscles, not momentum, to perform the exercise. A common mistake is to drop down quickly', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (310, 105, 1, 'Maintain Core Stability: Engage your core throughout the entire exercise. This will help maintain your body alignment and reduce the risk of lower back injuries. A common mistake is to let the hips sag or the back arch excessively, which can strain the spine.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (311, 105, 2, 'Controlled Movements: Lower your body towards the ground in a controlled manner until your chest nearly touches the floor. Push your body back up to the starting position as forcefully as you can. Avoid the mistake of rushing the movement or using momentum to lift yourself up, as this can lead to poor form and reduced effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (312, 105, 3, 'El', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (313, 106, 1, 'Engage Your Core: Before you push up, tighten your abdominal muscles. This will help to protect your lower back and also engage your core during the exercise. A common mistake is to forget about the core and focus only on the upper body, which can lead to lower back pain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (314, 106, 2, 'Correct Movement: Push up from your hands, extending your arms and lifting your upper body off the ground while keeping your hips and legs on the floor. Make sure to keep your elbows close to your body during this movement to avoid strain on the shoulders.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (315, 106, 3, 'Controlled Movement: Lower yourself back to the starting position in a controlled manner. Do not let gravity do the work for you. A common mistake is to drop down too quickly, which can lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (316, 106, 4, 'Breathe:', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (317, 107, 1, 'Hand Position: Your hands should be shoulder-width apart, directly under your shoulders. Placing your hands too wide apart can put excessive strain on your shoulders and elbows, while placing them too close can limit your range of motion and the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (318, 107, 2, 'Full Range of Motion: To get the most out of your push-ups, make sure you''re using a full range of motion. This means lowering your body until your chest almost touches the floor, then pushing back up to the original position. Half push-ups don''t engage your muscles to their full potential.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (319, 107, 3, 'Controlled Movement: Avoid the common mistake of rushing through your push-ups. Instead, control your movement on the way down and the way up', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (320, 108, 1, 'Maintain Proper Body Alignment: Keep your body in a straight line from your head to your heels. Avoid arching your back or sagging your hips, as this can lead to lower back injuries. Engage your core muscles to help maintain this alignment throughout the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (321, 108, 2, 'Control Your Movement: Don''t rush through the exercise. Lower your body in a controlled manner until your chest almost touches the floor, then push back up to the starting position. This not only maximizes muscle engagement but also reduces the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (322, 108, 3, 'Elbow Position: Keep your elbows close to your body as you perform the exercise. Flaring your elbows out can put unnecessary stress on your shoulder joints and reduce the effectiveness of the exercise on your tr', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (323, 109, 1, 'Maintain Core Stability: Engage your core throughout the entire movement. This will help to maintain proper form and protect your lower back. Mistake to avoid: Do not let your hips sag or your back arch during the exercise, as this can lead to lower back injuries.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (324, 109, 2, 'Controlled Movement: Lower your body until your chest nearly touches the bench. Push your body back up to the starting position. Make sure to perform this movement in a controlled manner to avoid injury and to maximize the effectiveness of the exercise. Mistake to avoid: Do not drop your body quickly or bounce at the', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (325, 110, 1, 'Master The Basics First: Start with mastering a basic handstand before moving on to the push-up variation. This helps to build the necessary strength and balance. A common mistake is to try the handstand push-up without being comfortable with a regular handstand.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (326, 110, 2, 'Use a Wall for Support: When starting out, use a wall for support. This will help you maintain balance and focus on your form. Slowly ease away from the wall as your strength and confidence increase. Avoid the mistake of trying handstand push-ups without support before you''re ready.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (327, 110, 3, 'Maintain Proper Form: Keep your body straight and your head in line with your spine. When lowering yourself, your elbows should not', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (328, 111, 1, 'Controlled Movement: The Pike-to-Cobra Push-up is not about speed, but about controlled, fluid movement. Rushing through the motions can lead to improper form and potential injury. Focus on each part of the movement, ensuring your muscles are engaged throughout.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (329, 111, 2, 'Proper Breathing: Breathing is an essential part of any exercise. Inhale as you start the downward movement from the pike position, and exhale as you push up into the cobra position. Proper breath control helps to maintain rhythm and provides the necessary oxygen to the muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (330, 111, 3, 'Modify if Needed: If', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (331, 112, 1, 'Avoid Locking Your Elbows: One common mistake people make while performing chest dips is locking their elbows at the top of the movement. This can put unnecessary strain on the joints and potentially lead to injury. Instead, keep a slight bend in your elbows even at the top of the movement to keep the tension on your muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (332, 112, 2, 'Control Your Movement: Don''t use momentum to perform the exercise. This is a common mistake and can lead to injury and diminished results. Instead, control your movement up and down, ensuring that your muscles are doing the', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (333, 113, 1, 'Controlled Movement: As you lower your body, your elbows should be bent at a 90-degree angle. Avoid going too low as this can strain your shoulders. It''s a common mistake to rush the exercise, but it''s important to maintain a controlled, steady pace to maximize muscle engagement and prevent injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (334, 113, 2, 'Keep Your Body Close: Your body should remain close to the bench or chair throughout the exercise. A common mistake is to move too far away, which can put unnecessary strain on your shoulders.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (335, 113, 3, 'Engage Your Core: Keep your abdominal muscles tight during the exercise. This will help to stabilize your body and reduce the risk of back injury. Many people forget to engage their', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (336, 114, 1, 'Lowering Your Body: Bend your elbows to slowly lower your body towards the floor until your elbows are at a 90-degree angle. Ensure your back is close to the bench throughout this movement.    Common Mistake: Some people tend to move their body too far away from the bench, which puts unnecessary strain on the shoulders.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (337, 114, 2, 'Maintaining Form: Keep your core engaged and your shoulders down and back during the exercise. This helps to maintain proper form and targets the triceps more effectively.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (338, 115, 1, 'Keep Elbows Close: A common mistake is flaring out the elbows, which can strain the shoulder joints. Instead, keep your elbows close to your body as you lower and raise your body. This will ensure that the focus of the exercise remains on your triceps.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (339, 115, 2, 'Controlled Movements: Avoid rushing through the motions. Lower your body in a slow, controlled manner and then push back up. This will help you to engage your muscles more effectively and reduce the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (340, 115, 3, 'Warm Up: Before doing any strength training exercise, it''s important to warm up your muscles to prevent injury. You can do this by doing some light cardio, such as', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (341, 116, 1, 'Correct Form: Start by sitting on the edge of the chair with your hands next to your hips. Move your hips forward, off the chair, and bend your elbows to lower your body towards the floor. Your elbows should be bent at a 90-degree angle. Keep your back close to the chair to avoid straining your shoulders, which is a common mistake.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (342, 116, 2, 'Engage your Core: It''s essential to keep your core engaged throughout the exercise to maintain balance and stability. This also helps to protect your lower back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (343, 116, 3, 'Controlled Movement: Avoid rushing through the dips. Instead, lower and lift your body in a slow, controlled manner. This is not only safer but also makes the exercise more effective as it engages your muscles throughout the movement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (344, 116, 4, 'Don''t', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (345, 117, 1, 'Engage Your Core: Before you start the exercise, make sure to engage your core. This means tightening your abdominal muscles as if you were about to be punched in the stomach. This will help to stabilize your body and protect your lower back during the exercise. A common mistake is to let the stomach relax, which can lead to lower back strain.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (346, 117, 2, 'Smooth Movement: The movement should be slow and controlled. As you slide your feet away from your body, your hips should lower', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (347, 118, 1, 'Correct Foot Placement: Place your feet completely on the pedals. Your feet should not hang off the edge, as this could lead to slipping and potentially cause injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (348, 118, 2, 'Controlled Movements: Avoid rushing through the exercise. Instead, focus on performing slow and controlled movements. This will help to engage your muscles properly and reduce the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (349, 118, 3, 'Core Engagement: Engage your core throughout the entire exercise. This will not only help to stabilize your body but also enhance the effectiveness of the workout by targeting your abdominal muscles.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (350, 118, 4, 'Avoid Overuse: Like any exercise equipment, it''s important not to overuse the Lever stepper. Start with shorter sessions and gradually increase your time as', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (351, 119, 1, 'Correct Form: Your elbows should be close to your ribs, hands slightly above your waistline, and you should slightly lean forward while jumping. Avoid jumping too high or kicking your feet back. This not only wastes energy but can also increase your risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (352, 119, 2, 'Start Slowly: If you''re a beginner, it''s important not to rush. Start with a basic jump and gradually incorporate different styles as you get more comfortable. Trying to perform complex jumps right off the bat can lead to injuries and discouragement.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (353, 119, 3, 'Warm-up and Cool-down: Like any other exercise, it''s crucial to warm up your body before you start jumping', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (354, 120, 1, 'Slow and Controlled Movements: Raise your heels off the ground and stand on your toes. Hold this position for a second and then lower your heels back to the ground. Make sure your movements are slow and controlled. Avoid bouncing or using momentum to lift your body, as this could lead to injury and decreases the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (355, 120, 2, 'Engage Your Core: Keep your abdominal muscles engaged to maintain balance and stability during the exercise. This will also help to protect your lower back.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (356, 120, 3, 'Focus on the Calf Muscles: Make sure to really focus on the calf muscles during the exercise. The aim is to feel a good contraction at the top of the movement and a stretch at the bottom. Avoid shifting the effort to other parts of your body, like your hips or thighs.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (357, 120, 4, '', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (358, 121, 1, 'Stretch One Leg at a Time: Extend one foot behind you, keeping it flat on the ground. Your other foot should be closer to the wall. This allows you to focus on each calf individually and ensures a more effective stretch.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (359, 121, 2, 'Keep Your Heel on the Ground: A common mistake is to lift the heel of the back foot off the ground. This reduces the effectiveness of the stretch. Make sure your heel stays firmly planted on the ground throughout the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (360, 121, 3, 'Maintain a Straight Back: Another common mistake is to lean into the wall with a rounded back. This can lead to back strain. Keep your back straight and only lean forward as far as you can without compromising your posture.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (361, 121, 4, 'Hold and Repeat: Hold the stretch for about 30 seconds', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (362, 122, 1, 'Controlled Movements: When performing the exercise, make sure to raise your heel as high as you can, then lower it back down slowly and controlled. Avoid bouncing or using momentum to lift your heel, as this can reduce the effectiveness of the exercise and potentially lead to injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (363, 122, 2, 'Foot Placement: Keep your supporting foot flat on the ground and make sure your weight is evenly distributed. Avoid rolling your foot inward or outward, as this can lead to ankle strain or injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (364, 122, 3, 'Regular Breathing: It might seem trivial, but maintaining regular breathing throughout the exercise is crucial. Inhale', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (365, 123, 1, 'Controlled Movement: Avoid bouncing or using momentum to lift the weight. This is a common mistake that can lead to injury and also reduces the effectiveness of the exercise. Instead, lift and lower the weight in a slow, controlled motion. This ensures that your calf muscles are doing the work and not your body''s momentum.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (366, 123, 2, 'Full Range of Motion: To get the most out of the exercise, make sure you are using a full range of motion. This means lowering your heels as far as comfortable to stretch your calf muscles, and then raising them as high as possible to contract the muscles. Not using a full range of motion can limit the exercise''s effectiveness.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (367, 124, 1, 'Full Range of Motion: For an effective calf raise, you need to go through the full range of motion. This means rising up on your toes as high as possible and then lowering your heels below the level of the step. Avoid the common mistake of not lowering your heels enough, which can limit the effectiveness of the exercise.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (368, 124, 2, 'Controlled Movements: Avoid rushing through the exercise. The movements should be slow and controlled, both when lifting and lowering the weight. This not only increases muscle engagement but also reduces the risk of injury.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (369, 124, 3, 'Weight Selection: Don''t overload the barbell. It''s a common mistake to think that more weight will lead to better results. However, using a weight that''s too heavy can compromise', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (370, 125, 1, 'Controlled Movement: Raise your heels as high as possible while maintaining balance. Pause for a second at the top and then slowly lower your heels below the level of the platform. Avoid rushing the movement. The slower and more controlled the movement, the more effective the exercise will be.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (371, 125, 2, 'Full Range of Motion: It''s important to go through the full range of motion, from the highest point of the heel raise to the lowest point where your heels are below the platform. This ensures you''re working the calf muscles to their full extent.', NULL);
INSERT INTO exercise_tip (id, exercise_id, tip_number, tip_text, tip_text_de) VALUES (372, 125, 3, 'Keep Your Knees Straight: Keep your knees straight but not locked throughout the exercise. Bending your knees can shift the focus away from your', NULL);
